import math

def f(x):
    return math.cos(x) - x

def secant_method(x0, x1):
    while abs(x1 - x0) > 1e-6:
        x_new = x1 - f(x1) * (x1 - x0) / (math.cos(x1) - x1)
        x0 = x1
        x1 = x_new
    return x1

